import logging
import os

import envoy_auth_external_auth_pb2 as pb2
import envoy_auth_external_auth_pb2_grpc as pb2_grpc
import grpc

class CustomAuthServer(pb2_grpc.ExternalAuthorizationServicer):

    def Check(self, request: pb2.CheckRequest, context: grpc.ServicerContext) -> pb2.CheckResponse:
        # Get custom header value
        custom_header_value = context.request().headers.get('custom-header')

        # Perform authorization logic based on custom header value
        if custom_header_value == 'authorized':
            return pb2.CheckResponse(status=pb2.CheckResponse.OK)
        else:
            return pb2.CheckResponse(status=pb2.CheckResponse.DENIED)

def serve():
    port = os.environ.get('PORT', '8080')
    server = grpc.server()
    pb2_grpc.add_ExternalAuthorizationServicer_to_server(CustomAuthServer(), server)
    server.add_insecure_port(f'[::]:{port}')
    server.start()
    server.wait_for_termination()

if __name__ == '__main__':
    logging.basicConfig(level=logging.INFO)
    serve()